@Component
public class CommentSanitizer {
    
    private static final String[] ALLOWED_TAGS = {
        "b", "i", "u", "em", "strong", "p", "br", "ul", "ol", "li"
    };
    
    private static final String[] ALLOWED_ATTRIBUTES = {
        "class", "id"
    };
    
    public String sanitizeComment(String comment) {
        if (comment == null || comment.trim().isEmpty()) {
            return comment;
        }
        
        try {
            String sanitized = Jsoup.clean(comment, 
                Whitelist.basic().addTags(ALLOWED_TAGS)
                    .addAttributes("p", ALLOWED_ATTRIBUTES)
                    .addAttributes("span", ALLOWED_ATTRIBUTES),
                new OutputSettings().prettyPrint(false)
            );
            return sanitized;
        } catch (Exception e) {
            return "";
        }
    }
}

@Controller
@RequestMapping("/comments")
public class SecureCommentController {
    
    @Autowired
    private CommentService commentService;
    
    @Autowired
    private CommentSanitizer commentSanitizer;
    
    @GetMapping
    public String showComments(Model model) {
        List<Comment> comments = commentService.getAllComments();
        model.addAttribute("comments", comments);
        return "comments";
    }
    
    @PostMapping("/add")
    public String addComment(@RequestParam("userName") String userName,
                           @RequestParam("commentText") String commentText,
                           Model model) {
        
        if (userName == null || userName.trim().isEmpty() || 
            commentText == null || commentText.trim().isEmpty()) {
            model.addAttribute("error", "All fields are required");
            return showComments(model);
        }
        
        userName = userName.trim();
        commentText = commentSanitizer.sanitizeComment(commentText);
        
        if (userName.length() > 100 || commentText.length() > 1000) {
            model.addAttribute("error", "Input exceeds maximum length");
            return showComments(model);
        }
        
        Comment comment = new Comment();
        comment.setUserName(userName);
        comment.setCommentText(commentText);
        
        try {
            commentService.saveComment(comment);
        } catch (Exception e) {
            model.addAttribute("error", "Failed to save comment");
            return showComments(model);
        }
        
        return "redirect:/comments";
    }
}